7	    const result = run({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums for main items (each + processing fee, no other modifiers)
15	  it.todo("quote single sword → 100 G base + 5 fee = 105 G");
16	  it.todo("quote single amulet → 60 G base + 5 fee = 65 G");
17	  it.todo("quote single staff → 80 G base + 5 fee = 85 G");
18	  it.todo("quote single potion → 40 G base + 5 fee = 45 G");
19	
20	  // Component base premiums
21	  it.todo("quote single rune → 25 G base + 5 fee = 30 G");
22	  it.todo("quote single moonstone → 25 G base + 5 fee = 30 G");
23	
24	  // Block of 3 alike components
25	  it.todo("quote 2 runes → 50 G base + 5 fee = 55 G");
26	  it.todo("quote 3 runes → 60 G base (block) + 5 fee = 65 G");
27	  it.todo("quote 4 runes → 100 G base (no block, requires exactly 3) + 5 fee = 105 G");
28	  it.todo("quote 7 runes → 175 G base + 5 fee = 180 G");
