37	  // High enchantment item-specific
38	  it.todo("quote sword enchantment 5 → 100 + 30 high-enchant + 5 fee = 135 G (threshold)");
39	  it.todo("quote sword enchantment 4 → 100 + 5 fee = 105 G (below threshold)");
40	  it.todo("quote cursed sword enchantment 5 → 100 + 50 + 30 + 5 = 185 G");
41	
42	  // Policy-wide modifiers
43	  it.todo("quote cursed sword + plain amulet → 160 base + 50 curse + 5 fee = 215 G");
44	  it.todo("quote single sword with customer 2 years → 100 - 20 loyalty + 5 fee = 85 G (threshold)");
