57	
58	  // Claims — standard reimbursement
59	  it.todo("claim regular sword damage 500 → payout 400 (full minus 100 deductible)");
60	  it.todo("claim rune damage 200 → payout 100 (full minus 100 deductible)");
61	
62	  // Claims — enchantment >= 8 (50%)
63	  it.todo("claim steel sword ench 9 damage 1000 → payout 400 (50% then deductible)");
64	
65	  // Claims — dragon material full
66	  it.todo("claim dragon sword ench 5 damage 800 → payout 700 (full then deductible)");
